7173 SCEV::NoWrapFlags ScalarEvolution::getNoWrapFlagsFromUB(const Value *V) {
7174   if (isa<ConstantExpr>(V)) return SCEV::FlagAnyWrap;
7175   const BinaryOperator *BinOp = cast<BinaryOperator>(V);
7176 
7177   // Return early if there are no flags to propagate to the SCEV.
7178   SCEV::NoWrapFlags Flags = SCEV::FlagAnyWrap;
7179   if (BinOp->hasNoUnsignedWrap())
7180     Flags = ScalarEvolution::setFlags(Flags, SCEV::FlagNUW);
7181   if (BinOp->hasNoSignedWrap())
7182     Flags = ScalarEvolution::setFlags(Flags, SCEV::FlagNSW);
7183   if (Flags == SCEV::FlagAnyWrap)
7184     return SCEV::FlagAnyWrap;
7185 
7186   return isSCEVExprNeverPoison(BinOp) ? Flags : SCEV::FlagAnyWrap;
7187 }
